<template>
  <div class="guide-home">
    <!-- 英雄区 -->
    <div class="guide-hero">
      <div class="guide-hero__icon">📐</div>
      <h1 class="guide-hero__title">FlowDesigner 使用手册</h1>
      <p class="guide-hero__desc">
        渐进式学习 <code>FlowDesignerLayout</code> 组件，从基础用法到高级技巧，逐步掌握流程设计器的全部能力。
      </p>
      <div class="guide-hero__actions">
        <RouterLink to="/guide/introduction" class="guide-hero__btn guide-hero__btn--primary">
          开始学习 →
        </RouterLink>
        <RouterLink to="/" class="guide-hero__btn guide-hero__btn--ghost">
          查看演示
        </RouterLink>
      </div>
    </div>

    <!-- 进度总览 -->
    <div class="guide-progress-bar">
      <span class="guide-progress-bar__label">学习进度</span>
      <div class="guide-progress-bar__track">
        <div class="guide-progress-bar__fill" :style="{ width: progressPercent + '%' }"></div>
      </div>
      <span class="guide-progress-bar__count">{{ readCount }} / {{ chapters.length }} 章节</span>
    </div>

    <!-- 章节卡片 -->
    <div class="guide-chapters">
      <RouterLink
        v-for="(item, index) in chapters"
        :key="item.path"
        :to="item.path"
        class="guide-chapter-card"
        :class="{ 'guide-chapter-card--read': isRead(item.path) }"
      >
        <div class="guide-chapter-card__header">
          <span class="guide-chapter-card__num">{{ item.num }}</span>
          <span v-if="isRead(item.path)" class="guide-chapter-card__badge guide-chapter-card__badge--done">已完成</span>
          <span v-else-if="index === firstUnread" class="guide-chapter-card__badge guide-chapter-card__badge--next">下一步</span>
        </div>
        <div class="guide-chapter-card__title">{{ item.title }}</div>
        <div class="guide-chapter-card__desc">{{ item.desc }}</div>
        <div class="guide-chapter-card__footer">
          <span class="guide-chapter-card__tag" v-for="tag in item.tags" :key="tag">{{ tag }}</span>
        </div>
      </RouterLink>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref, computed, onMounted } from 'vue'
import { RouterLink } from 'vue-router'

const chapters = [
  {
    num: '01', title: '认识 FlowDesignerLayout', path: '/guide/introduction',
    desc: '了解组件整体架构、布局区域划分与核心设计理念，建立全局认知。',
    tags: ['概览', '架构'],
  },
  {
    num: '02', title: '基础使用', path: '/guide/basic-usage',
    desc: '最小化运行示例、Props 说明与内嵌交互演示，快速跑通第一个流程。',
    tags: ['Props', '示例'],
  },
  {
    num: '03', title: 'FlowDesigner 参数与方法', path: '/guide/flowdesigner-api',
    desc: 'FlowDesigner 核心类的公共属性、方法与回调函数完整参考。',
    tags: ['API', '参考'],
  },
  {
    num: '04', title: '插槽系统', path: '/guide/slots',
    desc: '掌握 toolbar、palette、properties 等 6 个插槽及其作用域变量。',
    tags: ['Slots', '自定义'],
  },
  {
    num: '05', title: '权限系统', path: '/guide/permissions',
    desc: '三层合并策略，内置 design / readonly / preview 模式，支持自定义权限。',
    tags: ['Permissions', '模式'],
  },
  {
    num: '06', title: '事件与拦截器', path: '/guide/events',
    desc: '生命周期事件、before/after 钩子，以及 preventDefault 拦截机制。',
    tags: ['Events', '拦截器'],
  },
  {
    num: '07', title: '快捷键', path: '/guide/shortcuts',
    desc: '内置快捷键速查表，以及如何自定义覆盖键位绑定。',
    tags: ['Shortcuts', '键盘'],
  },
  {
    num: '08', title: '进阶技巧', path: '/guide/advanced',
    desc: '通过 ref 访问完整 API、动态切换权限、性能最佳实践。',
    tags: ['进阶', 'API'],
  },
]

const READ_KEY = 'guide_read_chapters'
const readSet = ref<Set<string>>(new Set())

function loadRead() {
  try {
    const raw = localStorage.getItem(READ_KEY)
    readSet.value = new Set(raw ? JSON.parse(raw) : [])
  } catch {
    readSet.value = new Set()
  }
}

function isRead(path: string) { return readSet.value.has(path) }

const readCount = computed(() => chapters.filter(c => isRead(c.path)).length)
const progressPercent = computed(() => Math.round((readCount.value / chapters.length) * 100))
const firstUnread = computed(() => chapters.findIndex(c => !isRead(c.path)))

onMounted(() => loadRead())
</script>

<style scoped>
.guide-home {
  min-height: 100vh;
  padding: 48px 48px 80px;
  background: #f5f6fa;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
}

.guide-hero {
  text-align: center;
  padding: 48px 0 40px;
}
.guide-hero__icon { font-size: 52px; margin-bottom: 16px; }
.guide-hero__title { font-size: 32px; font-weight: 700; color: #1a1a2e; margin: 0 0 16px; }
.guide-hero__desc {
  font-size: 16px; color: #666; max-width: 560px; margin: 0 auto 28px; line-height: 1.7;
}
.guide-hero__desc code {
  background: #eef2ff; color: #1677ff; padding: 2px 6px; border-radius: 4px; font-size: 14px;
}
.guide-hero__actions { display: flex; gap: 12px; justify-content: center; }
.guide-hero__btn {
  display: inline-flex; align-items: center; padding: 10px 24px;
  border-radius: 8px; font-size: 14px; font-weight: 500; text-decoration: none; transition: all 0.2s;
}
.guide-hero__btn--primary { background: #1677ff; color: #fff; }
.guide-hero__btn--primary:hover { background: #0958d9; }
.guide-hero__btn--ghost { background: #fff; color: #555; border: 1px solid #d9d9d9; }
.guide-hero__btn--ghost:hover { border-color: #1677ff; color: #1677ff; }

.guide-progress-bar {
  display: flex; align-items: center; gap: 12px;
  max-width: 480px; margin: 0 auto 40px; padding: 14px 20px;
  background: #fff; border-radius: 10px; box-shadow: 0 1px 6px rgba(0,0,0,0.06);
}
.guide-progress-bar__label { font-size: 13px; color: #888; white-space: nowrap; }
.guide-progress-bar__track {
  flex: 1; height: 6px; background: #f0f0f0; border-radius: 3px; overflow: hidden;
}
.guide-progress-bar__fill { height: 100%; background: #1677ff; border-radius: 3px; transition: width 0.4s; }
.guide-progress-bar__count { font-size: 12px; color: #888; white-space: nowrap; }

.guide-chapters {
  display: grid; grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: 16px; max-width: 1100px; margin: 0 auto;
}
.guide-chapter-card {
  background: #fff; border-radius: 12px; padding: 24px;
  text-decoration: none; color: inherit;
  border: 2px solid transparent;
  box-shadow: 0 1px 6px rgba(0,0,0,0.06);
  transition: all 0.2s; display: block;
}
.guide-chapter-card:hover { border-color: #1677ff; box-shadow: 0 4px 16px rgba(22,119,255,0.12); transform: translateY(-2px); }
.guide-chapter-card--read { border-color: #b7eb8f; }

.guide-chapter-card__header { display: flex; align-items: center; gap: 8px; margin-bottom: 12px; }
.guide-chapter-card__num { font-size: 12px; color: #bbb; font-weight: 600; }
.guide-chapter-card__badge {
  font-size: 11px; padding: 2px 8px; border-radius: 10px; font-weight: 500;
}
.guide-chapter-card__badge--done { background: #f6ffed; color: #52c41a; }
.guide-chapter-card__badge--next { background: #e6f0ff; color: #1677ff; }

.guide-chapter-card__title { font-size: 16px; font-weight: 600; color: #1a1a2e; margin-bottom: 8px; }
.guide-chapter-card__desc { font-size: 13px; color: #666; line-height: 1.6; margin-bottom: 16px; }
.guide-chapter-card__footer { display: flex; gap: 6px; flex-wrap: wrap; }
.guide-chapter-card__tag {
  font-size: 11px; padding: 2px 8px; background: #f5f5f5;
  color: #888; border-radius: 4px;
}
</style>
